const $=(s)=>document.querySelector(s); const $$=(s)=>Array.from(document.querySelectorAll(s));
const fmtTeam=(k)=>k.replace('frc','');
const toLocal=(secs)=>secs? new Date(secs*1000).toLocaleString() : '-';
const sum=(a)=>a.reduce((x,y)=>x+y,0); const mean=(a)=>a.length? sum(a)/a.length:0; const stdev=(a)=>{const m=mean(a); return Math.sqrt(mean(a.map(x=>(x-m)*(x-m))));};
const clamp=(x,lo,hi)=>Math.max(lo,Math.min(hi,x)); const logistic=(x)=>1/(1+Math.pow(Math.E,-x));
